        "--api-extra-params", API_EXTRA_PARAMS,
        "--verify-correction-kwargs", VERIFY_CORRECTION_KWARGS,
        "--verbose",
    ]
    _run_cmd(run_eval_cmd)
    # 读取最后结果
    result = _load_latest_result(eval_output_dir)
    # 计算 metrics
    score = _to_float_nan(result.get("score", 0.0))
    if math.isnan(score):
        score = 0.0
    metrics: Dict[str, float] = {"combined_score": float(score)}
    targets: List[str] = []
    if isinstance(ground_truth, dict) and isinstance(ground_truth.get("targets"), list):
        targets = [str(x) for x in ground_truth["targets"]]
    for k in targets:
        metrics[k] = float("nan")
    raw = _extract_last_metrics_dict_from_result(result)
    if isinstance(raw, dict):
        for k in targets:
            if k in raw:
                metrics[k] = _to_float_nan(raw[k])
    # 写 meta.json（固定索引）
    meta = {
        "ts": time.time(),
        "run_id": run_id,
        "iteration": iteration,
        "sample_id": sample_id,
        "metrics": metrics,
        "paths": {
            "run_dir": run_dir,
            "dataset_path": dataset_path,
            "eval_output_dir": eval_output_dir,
            "program_path": program_path,
        },
    }
    _write_json(os.path.join(run_dir, "meta.json"), meta)
    # append 汇总 jsonl（含 result，便于你后处理提取最终参数）
    rollout_line = {
        "ts": meta["ts"],
        "run_id": run_id,
        "iteration": iteration,
        "sample_id": sample_id,
        "metrics": metrics,
        "input_variables": patch_vars,
        "merged_variables": merged_vars,
        "result": result,
        "paths": meta["paths"],
    }
    _append_jsonl(ROLLOUT_JSONL, rollout_line)
    return metrics
```

你这个 evaluator **已经能把 rollout 写出来**，但在“一个 task 内多并发 + 多进程”场景下，有两个现实问题需要你现在就修一下，否则后面手动提取会很痛：

1) **同一个 task 内多进程并发写 `rollouts.jsonl` 可能写坏（行交错）**  
2) 你要做“方案 B：每个 task 一个 rollouts.jsonl”，现在是写死同一个 `RUN_ROOT/rollouts.jsonl`，会跨 task 冲突

你不想再改其它文件的话，最小改动就是：**只改这个 evaluator**，让它：
- 自动按 `OPENEOLVE_TASK_IDX`（你 launcher 里本来就有 `--task-idx`，加一行 env 就行；如果你不想改 launcher，也可以默认 0）
- 把 `RUN_ROOT` 变成 `.../acs_ibc_rollouts/task_XX/`
- 给 `_append_jsonl` 加 `fcntl.flock` 文件锁，保证并发安全

另外顺手加一个很有用的索引：把 `program_obj` 里如果有 `_child_id/_parent_id/_iteration` 直接写入 rollouts 行（即使现在没有，也不影响）。

