    _write_json(os.path.join(run_dir, "meta.json"), meta)
    rollout_line = {
        "ts": meta["ts"],
        "run_id": run_id,
        "task_idx": _TASK_IDX,
        "iteration": iteration,
        "sample_id": sample_id,
        "metrics": metrics,
        "index": extra_index,
        "input_variables": patch_vars,
        "merged_variables": merged_vars,
        "result": result,
        "paths": meta["paths"],
    }
    _append_jsonl(ROLLOUT_JSONL, rollout_line)
    return metrics
